options.systemMessage:
You are an expert in electronic waste (e-waste) material analysis and component recovery.

When given an image of any e-waste device, analyse it and return ONLY valid JSON (no markdown, no backticks) with this exact structure:

{
  "image_name": "device",
  "device_type": "describe the exact device type here e.g. laptop motherboard, USB hub, CRT monitor, inkjet printer, power bank, etc.",
  "metals_detected": [
    { "name": "Copper", "symbol": "Cu", "recoverable": true, "estimated_weight_g": 45, "percentage": 18 }
  ],
  "total_recoverable_percentage": 72,
  "negative_impacts": [
    "Toxic fumes during smelting"
  ],
  "reusable_components": [
    {
      "name": "Component name",
      "description": "What it is and where it is on this specific device",
      "testing_method": "How to test if it still works",
      "condition_check": "What to look for to confirm it is reusable",
      "search_image_query": "specific search query to find reference image of this exact component e.g. laptop DDR4 RAM module"
    }
  ],
  "summary": "Brief 2-sentence summary of the device and its metal composition."
}

Identify ALL reusable components specific to this exact device. Be very specific — a component on a laptop motherboard is different from one on a phone charger. List every component that could realistically be salvaged and reused.

parameters.jsCode:
const raw = $input.item.json.output || $input.item.json.text || '';

let analysis;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { error: 'Parse failed', raw };
}

let imgSrc = '';
try {
  const nodes = ['AI Agent — Grok Vision', 'Webhook — Receive Image'];
  for (const nodeName of nodes) {
    try {
      const item = $(nodeName).item;
      if (item && item.binary) {
        const key = Object.keys(item.binary)[0];
        if (key && item.binary[key].data) {
          imgSrc = `data:${item.binary[key].mimeType};base64,${item.binary[key].data}`;
          break;
        }
      }
    } catch(e2) { continue; }
  }
} catch(e) { imgSrc = ''; }

const original_name = $('Webhook — Receive Image').item.json.body?.original_name || '';

return {
  json: {
    analysis,
    original_name,
    imgSrc
  }
};

const analysis   = $('Parse AI Response').item.json.analysis;
const imgName    = $('Parse AI Response').item.json.original_name || 'component';
const marketData = $input.item.json;
const imgSrc     = $('Parse AI Response').item.json.imgSrc || '';

const metals    = (analysis.metals_detected || []).map(m => m.name);
const pcts      = (analysis.metals_detected || []).map(m => m.percentage || 0);
const weights   = (analysis.metals_detected || []).map(m => m.estimated_weight_g || 0);
const pricesRaw = (marketData && marketData.prices) ? marketData.prices : {};
const deviceType = analysis.device_type || 'Electronic Device';

const metalsRows = (analysis.metals_detected || []).map(m => `
<tr class="mrow">
  <td><strong>${m.name}</strong> <span class="sym">(${m.symbol})</span></td>
  <td>${m.recoverable
    ? '<span class="badge green">✓ Recoverable</span>'
    : '<span class="badge red">✗ Non-Recoverable</span>'}</td>
  <td>${m.estimated_weight_g ?? '—'} g</td>
  <td>${m.percentage ?? '—'}%</td>
</tr>`).join('');

const recov    = (analysis.metals_detected || []).filter(m => m.recoverable).map(m => m.name);
const nonRecov = (analysis.metals_detected || []).filter(m => !m.recoverable).map(m => m.name);
const impacts  = (analysis.negative_impacts || []).map(i => `<div class="impact-row">⚠ ${i}</div>`).join('');

// Reusable components from AI — dynamic, device-specific
const reusableComponents = analysis.reusable_components || [];
const reusableCards = reusableComponents.map((r, i) => {
  const query = encodeURIComponent(r.search_image_query || r.name);
  const unsplashUrl = `https://source.unsplash.com/300x200/?${query}`;
  return `
<div class="reuse-card animate" style="animation-delay:${0.08*i}s">
  <div class="reuse-img-wrap">
    <img
      src="${unsplashUrl}"
      alt="${r.name}"
      loading="lazy"
      onerror="this.style.display='none';this.nextElementSibling.style.display='flex'"
    />
    <div class="reuse-img-fallback" style="display:none">🔧</div>
  </div>
  <div class="reuse-info">
    <div class="reuse-name">${r.name}</div>
    <div class="reuse-desc">${r.description || ''}</div>
    <div class="reuse-test"><span class="reuse-label">🔬 Test:</span> ${r.testing_method || '—'}</div>
    <div class="reuse-test"><span class="reuse-label">👁 Check:</span> ${r.condition_check || '—'}</div>
    <span class="badge green" style="margin-top:8px;font-size:10px">♻ Reusable</span>
  </div>
</div>`;
}).join('') || '<div style="color:var(--muted);font-size:13px">No reusable components identified by AI for this device.</div>';

// Research papers — Google Scholar search per metal (always works)
const papersByMetal = (analysis.metals_detected || []).map(m => {
  const searches = [
    {
      title: `Recovery of ${m.name} from Electronic Waste — Comprehensive Review`,
      journal: 'Google Scholar Search · Peer-reviewed papers',
      readUrl: `https://scholar.google.com/scholar?q=${encodeURIComponent(m.name + ' recovery electronic waste')}`,
      dlUrl: `https://scholar.google.com/scholar?q=${encodeURIComponent(m.name + ' recovery e-waste free pdf')}`,
      tags: [m.name, 'E-Waste', 'Recovery'],
    },
    {
      title: `Hydrometallurgical Extraction of ${m.name} from PCB Waste`,
      journal: 'Google Scholar Search · Hydrometallurgy',
      readUrl: `https://scholar.google.com/scholar?q=${encodeURIComponent(m.name + ' hydrometallurgy printed circuit board leaching')}`,
      dlUrl: `https://scholar.google.com/scholar?q=${encodeURIComponent(m.name + ' hydrometallurgy PCB leaching open access pdf')}`,
      tags: [m.name, 'Hydrometallurgy', 'PCB'],
    },
    {
      title: `Environmental Impact of ${m.name} Recovery — Life Cycle Assessment`,
      journal: 'Google Scholar Search · Environmental Science',
      readUrl: `https://scholar.google.com/scholar?q=${encodeURIComponent(m.name + ' e-waste life cycle assessment environmental impact')}`,
      dlUrl: `https://scholar.google.com/scholar?q=${encodeURIComponent(m.name + ' LCA environmental impact open access')}`,
      tags: [m.name, 'LCA', 'Environment'],
    },
    {
      title: `Bioleaching of ${m.name} from Waste Electronic Equipment`,
      journal: 'Google Scholar Search · Bioresource Technology',
      readUrl: `https://scholar.google.com/scholar?q=${encodeURIComponent(m.name + ' bioleaching waste electronic equipment bacteria')}`,
      dlUrl: `https://scholar.google.com/scholar?q=${encodeURIComponent(m.name + ' bioleaching WEEE free pdf')}`,
      tags: [m.name, 'Bioleaching', 'WEEE'],
    },
  ];
  return searches.map(p => ({...p, metal: m.name}));
}).flat();

const paperCards = papersByMetal.map((p,i) => `
<div class="paper-card" data-metal="${p.metal}">
  <div class="paper-title">
    <a href="${p.readUrl}" target="_blank" rel="noopener" class="paper-link">${p.title}</a>
  </div>
  <div class="paper-meta">${p.journal}</div>
  <div class="paper-tags">${p.tags.map(t=>`<span class="paper-tag">${t}</span>`).join('')}</div>
  <div class="paper-actions">
    <a href="${p.readUrl}" target="_blank" class="paper-btn read-btn">📖 Search Papers</a>
    <a href="${p.dlUrl}" target="_blank" class="paper-btn dl-btn">⬇ Find Free PDF</a>
  </div>
</div>`).join('');

const metalFilterBtns = ['All', ...metals].map((m,i) =>
  `<button class="ftab${i===0?' active':''}" onclick="filterPapers('${m}',this)">${m}</button>`
).join('');

