  setTimeout(()=>{
    const i=document.getElementById('intro');
    if(i){i.classList.add('gone');setTimeout(()=>i.remove(),1100);}
  },2600);
});

const io=new IntersectionObserver(entries=>{
  entries.forEach(e=>{if(e.isIntersecting)e.target.classList.add('visible');});
},{threshold:0.08});
document.querySelectorAll('.animate').forEach(el=>io.observe(el));

(function(){
  const zone=document.getElementById('dropZone');
  const inp=document.getElementById('drop-input');
  const img=document.getElementById('comp-img');
  const hint=document.getElementById('drop-hint');
  const bar=document.getElementById('img-info-bar');
  if(!zone||!inp)return;
  const ALLOWED=new Set(['image/jpeg','image/png','image/webp','image/gif','image/bmp']);
  const MAGIC=[
    {mime:'image/jpeg',off:0,bytes:[0xFF,0xD8,0xFF]},
    {mime:'image/png',off:0,bytes:[0x89,0x50,0x4E,0x47]},
    {mime:'image/gif',off:0,bytes:[0x47,0x49,0x46]},
    {mime:'image/bmp',off:0,bytes:[0x42,0x4D]},
    {mime:'image/webp',off:8,bytes:[0x57,0x45,0x42,0x50]},
  ];
  function checkMagic(file){
    return new Promise(res=>{
      const r=new FileReader();
      r.onload=e=>{
        const buf=new Uint8Array(e.target.result);
        for(const s of MAGIC){
          const sl=buf.slice(s.off,s.off+s.bytes.length);
          if(s.bytes.every((b,i)=>sl[i]===b)){res(true);return;}
        }
        res(false);
      };
      r.readAsArrayBuffer(file.slice(0,16));
    });
  }
  async function loadFile(file){
    if(!ALLOWED.has(file.type)){alert('Only image files allowed.');return;}
    const ok=await checkMagic(file);
    if(!ok){alert('File failed security check.');return;}
    const url=URL.createObjectURL(file);
    if(img){img.src=url;img.style.display='block';}
    if(hint)hint.style.display='none';
    if(bar){
      const d=new Date();
      bar.innerHTML='<strong>File:</strong> '+file.name+' &nbsp;|&nbsp; <strong>Size:</strong> '+(file.size/1024).toFixed(1)+' KB &nbsp;|&nbsp; <strong>Date:</strong> '+d.toLocaleDateString()+' &nbsp;|&nbsp; <span style="color:var(--green)">✓ Secure — no hidden data stored</span>';
    }
  }
  zone.addEventListener('click',()=>inp.click());
  inp.addEventListener('change',e=>{if(e.target.files[0])loadFile(e.target.files[0]);});
  zone.addEventListener('dragover',e=>{e.preventDefault();zone.classList.add('dragover');});
  zone.addEventListener('dragleave',()=>zone.classList.remove('dragover'));
  zone.addEventListener('drop',e=>{
    e.preventDefault();zone.classList.remove('dragover');
    const f=e.dataTransfer.files[0];if(f)loadFile(f);
  });
})();

