const COLORS=['#4f8ef7','#7c3aed','#22c55e','#f59e0b','#ef4444','#06b6d4','#ec4899','#84cc16'];
const metals=${JSON.stringify(metals)};
const pcts=${JSON.stringify(pcts)};
const weights=${JSON.stringify(weights)};
const pricesRaw=${JSON.stringify(pricesRaw)};
let chartsRendered=false;

function renderCharts(){
  if(chartsRendered)return;
  chartsRendered=true;
  Plotly.newPlot('chart-pie',[{
    type:'pie',labels:metals,values:pcts,marker:{colors:COLORS},
    textinfo:'label+percent',hole:0.45,textfont:{color:'#e2e8f0'},
    hovertemplate:'<b>%{label}</b><br>%{value}%<extra></extra>'
  }],{paper_bgcolor:'transparent',plot_bgcolor:'transparent',
    font:{color:'#94a3b8'},margin:{t:10,b:10,l:10,r:10},showlegend:false
  },{responsive:true,displayModeBar:false});

  Plotly.newPlot('chart-bar',[{
    type:'bar',x:metals,y:weights,marker:{color:COLORS,opacity:0.85},
    text:weights.map(w=>w+'g'),textposition:'outside'
  }],{paper_bgcolor:'transparent',plot_bgcolor:'rgba(10,16,32,0.6)',
    font:{color:'#94a3b8'},margin:{t:20,b:40,l:45,r:10},
    xaxis:{gridcolor:'#1a2840'},yaxis:{gridcolor:'#1a2840',title:'grams'}
  },{responsive:true,displayModeBar:false});

  let traces=[],mn='',mx='';
  Object.entries(pricesRaw).forEach(([metal,pts],i)=>{
    if(!Array.isArray(pts))return;
    const dx=pts.map(p=>p.date),px=pts.map(p=>p.price);
    if(!mn||dx[0]<mn)mn=dx[0];
    if(!mx||dx[dx.length-1]>mx)mx=dx[dx.length-1];
    traces.push({type:'scatter',mode:'lines',name:metal,x:dx,y:px,
      line:{color:COLORS[i%COLORS.length],width:2},
      hovertemplate:'<b>%{fullData.name}</b><br>%{x}<br>$%{y:,.2f}/kg<extra></extra>'});
  });
  Plotly.newPlot('chart-market',traces,{
    paper_bgcolor:'transparent',plot_bgcolor:'rgba(10,16,32,0.6)',
    font:{color:'#94a3b8'},margin:{t:10,b:40,l:70,r:10},
    xaxis:{gridcolor:'#1a2840',rangeslider:{bgcolor:'#0d1526'}},
    yaxis:{gridcolor:'#1a2840',title:'USD / kg'},
    legend:{bgcolor:'rgba(13,21,38,0.9)',bordercolor:'#1a2840',borderwidth:1},
    hovermode:'x unified'
  },{responsive:true});
  if(mn)document.getElementById('df').value=mn;
  if(mx)document.getElementById('dt').value=mx;
}

const chartObs=new IntersectionObserver(entries=>{
  entries.forEach(e=>{if(e.isIntersecting)renderCharts();});
},{threshold:0.1});
const chartEl=document.getElementById('chart-pie');
if(chartEl)chartObs.observe(chartEl);

function applyFilter(){
  Plotly.relayout('chart-market',{'xaxis.range':[document.getElementById('df').value,document.getElementById('dt').value]});
}
function resetFilter(){
  Plotly.relayout('chart-market',{'xaxis.autorange':true});
}
